/**
 * Sample: send WhatsApp messages using an API key generated by this system.
 *
 * Usage:
 *   1. Paste your generated API key into API_KEY below.
 *   2. Make sure backend is running and WhatsApp is connected in dashboard.
 *   3. Run: node api-key-send-sample.js
 *
 * Requirements:
 *   1. Backend server is running.
 *   2. The API key is active.
 *   3. The matching user's WhatsApp is connected in the dashboard.
 */

const API_KEY = 'wsa_live_79f28684092e156fc2abf8a6cff93147';
const BASE_URL = 'http://localhost:5000';
const NUMBERS = ['+919327201924'];
const MESSAGE = 'hello';

const endpoint = `${BASE_URL.replace(/\/$/, '')}/api/whatsapp/send-via-api`;

const fail = (message) => {
  console.error(`Error: ${message}`);
  process.exitCode = 1;
};

const sendMessage = async () => {
  if (!API_KEY) {
    fail('Missing API key. Paste your generated API key into API_KEY in this file.');
    return;
  }

  if (API_KEY === 'PASTE_YOUR_GENERATED_API_KEY_HERE') {
    fail('Replace PASTE_YOUR_GENERATED_API_KEY_HERE with your generated API key.');
    return;
  }

  const response = await fetch(endpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': API_KEY,
    },
    body: JSON.stringify({
      numbers: NUMBERS,
      message: MESSAGE,
    }),
  });

  const text = await response.text();
  let body;
  try {
    body = text ? JSON.parse(text) : {};
  } catch {
    body = { raw: text };
  }

  console.log('Endpoint:', endpoint);
  console.log('Status:', response.status);
  console.log('Response:', JSON.stringify(body, null, 2));

  if (!response.ok) {
    process.exitCode = 1;
  }
};

sendMessage().catch((error) => {
  fail(error.message);
});
